SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW vm_mem_m_member_member_refer (membership_no_ref, membership_no, seq_no, memname, share_bal, loan_bal, dep_bal, div_bal) AS SELECT sc_mem_m_member_member_refer.membership_no_ref,
         sc_mem_m_member_member_refer.membership_no,  
         sc_mem_m_member_member_refer.seq_no , 
         pka_com_function.fp_get_member_name( sc_mem_m_member_member_refer.membership_no) as memname,   
         sc_mem_m_share_mem.share_stock   as share_bal
       
        , coalesce( ( select sum( principal_balance )
                FROM sc_lon_m_loan_card
                where principal_balance > 0
                and membership_no =  sc_mem_m_member_member_refer.membership_no ) , 0.00 ) as loan_bal

        , coalesce( ( select sum( deposit_balance )
                from sc_dep_m_creditor
                where deposit_balance > 0
                and membership_no =  sc_mem_m_member_member_refer.membership_no ) , 0.00 ) as dep_bal


        , coalesce( ( select sum( item_amount )
                from sc_mem_m_capital_pay
                where item_amount > 0
                and account_year = (  select max( lon_year )  from sc_mem_m_capital_rate )
                and membership_no =  sc_mem_m_member_member_refer.membership_no  ) , 0.00 ) as div_bal


    FROM sc_mem_m_member_member_refer  
    ,sc_mem_m_membership_registered
    ,sc_mem_m_share_mem
   WHERE  1=1
and sc_mem_m_membership_registered.member_status_code = '0'    
and sc_mem_m_membership_registered.membership_no  = sc_mem_m_share_mem.membership_no
and sc_mem_m_membership_registered.membership_no  = sc_mem_m_member_member_refer.membership_no
and sc_mem_m_member_member_refer.refer_status = '0'
--AND sc_mem_m_member_member_refer.membership_no_ref = '002973'
;

